import sys


class Solution:
    def __init__(self):
        self.s = []

    def pop(self):
        if not self.isEmpty():
            self.s.pop()
        else:
            raise IndexError('pop from an empty stack')

    def isEmpty(self):
        return len(self.s) == 0

    def size(self):
        return len(self.s)


if __name__ == '__main__':
    for _ in range(int(input())):
        n = int(input())
        while n > 0:
            n -= 1
            s = Solution()
            print('Empty stack' if s.isEmpty() else '1')
            s.pop()
            print(s.size())
            s.pop()
            print(s.size())
            s.pop()
            print(s.size())

