// -*- coding: utf-8 -*-

#include <iostream>
#include <vector>
using namespace std;

class Solution {
    private: vector<int> s;
    public: bool isEmpty() {
        return s.empty();
    }
    void pop() {
        if (!isEmpty()) {
            s.pop_back();
        } else {
            throw runtime_error('pop from an empty stack');
        }
    }
    int size() {
        return s.size();
    }
};

int main() {
    ios::sync_with_stdio(0);
    cin.tie(0);
    int t;
    cin >> t;
    while (t--)
    {
        int n;
        cin >> n;
        while (n--)
        {
            Solution s;
            if (s.isEmpty())
                cout << 'Empty stack' << endl;
            else
                cout << '1' << endl;
            s.pop();
            cout << s.size() << endl;
            s.pop();
            cout << s.size() << endl;
            s.pop();
            cout << s.size() << endl;
        }
    }
    return 0;
}
